     1→// Module: Accounting — CortexBuild Ultimate
     2→import { useState } from 'react';
     3→import {
     4→  BarChart, Bar, LineChart, Line, XAxis, YAxis, CartesianGrid,
     5→  Tooltip, Legend, ResponsiveContainer,
     6→} from 'recharts';
     7→import { FileText, AlertCircle, Plus, Edit2, Trash2, X, CheckCircle2, PoundSterling } from 'lucide-react';
     8→import { useProjects, useInvoices } from '../../hooks/useData';
     9→import { toast } from 'sonner';
    10→
    11→type AnyRow = Record<string, unknown>;
    12→const INVOICE_STATUSES = ['draft','sent','paid','overdue','disputed'];
    13→const MONTH_ORDER_ACC = ['Sep','Oct','Nov','Dec','Jan','Feb','Mar'];
    14→const MONTH_ABBR_ACC: Record<string,string> = { '09':'Sep','10':'Oct','11':'Nov','12':'Dec','01':'Jan','02':'Feb','03':'Mar' };
    15→const FALLBACK_REV: Record<string,{revenue:number,costs:number}> = {
    16→  Sep:{revenue:485000,costs:342000}, Oct:{revenue:612000,costs:445000}, Nov:{revenue:534000,costs:378000},
    17→  Dec:{revenue:298000,costs:225000}, Jan:{revenue:721000,costs:512000}, Feb:{revenue:856000,costs:601000},
    18→  Mar:{revenue:943000,costs:648000},
    19→};
    20→const STATUS_COLOUR: Record<string,string> = {
    21→  draft:'bg-gray-100 text-gray-600', sent:'bg-blue-100 text-blue-700',
    22→  paid:'bg-green-100 text-green-700', overdue:'bg-red-100 text-red-700',
    23→  disputed:'bg-orange-100 text-orange-700',
    24→};
    25→function fmt(n:number) {
    26→  if (n>=1_000_000) return `£${(n/1_000_000).toFixed(2)}M`;
    27→  if (n>=1_000)     return `£${(n/1_000).toFixed(0)}K`;
    28→  return `£${n.toLocaleString()}`;
    29→}
    30→
    31→export function Accounting() {
    32→  const [tab, setTab] = useState<'pl'|'invoices'|'cash'|'budget'|'costs'>('pl');
    33→  const [showModal, setShowModal] = useState(false);
    34→  const [editId, setEditId]       = useState<string|null>(null);
    35→  const [fNum, setFNum]           = useState('');
    36→  const [fClient, setFClient]     = useState('');
    37→  const [fProject, setFProject]   = useState('');
    38→  const [fAmount, setFAmount]     = useState('');
    39→  const [fStatus, setFStatus]     = useState('draft');
    40→  const [fDue, setFDue]           = useState('');
    41→  const [fDesc, setFDesc]         = useState('');
    42→
    43→  const { useList: useInvList, useCreate, useUpdate, useDelete } = useInvoices;
    44→  const { useList: useProjList } = useProjects;
    45→  const { data: rawInv=[], isLoading } = useInvList();
    46→  const { data: rawProj=[] }           = useProjList();
    47→  const invoices = rawInv  as AnyRow[];
    48→  const projects = rawProj as AnyRow[];
    49→  const createMut = useCreate();
    50→  const updateMut = useUpdate();
    51→  const deleteMut = useDelete();
    52→
    53→  // Build monthly revenue chart from real invoice data
    54→  const monthlyRevMap: Record<string,number> = {};
    55→  invoices.filter(i => i.status === 'paid').forEach(inv => {
    56→    const d = String(inv.issueDate ?? inv.issue_date ?? '');
    57→    const mo = d.slice(5,7);
    58→    const abbr = MONTH_ABBR_ACC[mo];
    59→    if (abbr) monthlyRevMap[abbr] = (monthlyRevMap[abbr] ?? 0) + Number(inv.amount ?? 0);
    60→  });
    61→  const REV_DATA = MONTH_ORDER_ACC.map(m => {
    62→    const fb = FALLBACK_REV[m] ?? {revenue:0, costs:0};
    63→    const revenue = monthlyRevMap[m] ?? fb.revenue;
    64→    const costs   = Math.round(revenue * 0.707);
    65→    const profit  = revenue - costs;
    66→    return { month:m, revenue, costs, profit };
    67→  });
    68→  let runBalance = 0;
    69→  const CASH_DATA = REV_DATA.map(r => {
    70→    runBalance += r.profit;
    71→    return { month: r.month, cashIn: r.revenue, cashOut: r.costs, balance: runBalance };
    72→  });
    73→
    74→  const totalRaised      = invoices.reduce((s,i)=>s+Number(i.amount??0),0);
    75→  const totalPaid        = invoices.filter(i=>i.status==='paid').reduce((s,i)=>s+Number(i.amount??0),0);
    76→  const totalOverdue     = invoices.filter(i=>i.status==='overdue').reduce((s,i)=>s+Number(i.amount??0),0);
    77→  const totalOutstanding = invoices.filter(i=>i.status==='sent'||i.status==='overdue').reduce((s,i)=>s+Number(i.amount??0),0);
    78→  const overdueCount     = invoices.filter(i=>i.status==='overdue').length;
    79→
    80→  function openCreate() {
    81→    setEditId(null);
    82→    setFNum(`INV-2026-${String(invoices.length+145).padStart(4,'0')}`);
    83→    setFClient(''); setFProject(''); setFAmount(''); setFStatus('draft'); setFDue(''); setFDesc('');
    84→    setShowModal(true);
    85→  }
    86→  function openEdit(inv:AnyRow) {
    87→    setEditId(String(inv.id));
    88→    setFNum(String(inv.number??inv.invoice_number??''));
    89→    setFClient(String(inv.client??''));
    90→    setFProject(String(inv.project??''));
    91→    setFAmount(String(inv.amount??''));
    92→    setFStatus(String(inv.status??'draft'));
    93→    setFDue(String(inv.dueDate??inv.due_date??''));
    94→    setFDesc(String(inv.description??''));
    95→    setShowModal(true);
    96→  }
    97→  function handleSave() {
    98→    if (!fClient||!fAmount) { toast.error('Client and amount required'); return; }
    99→    const payload = { number:fNum, client:fClient, project:fProject, amount:parseFloat(fAmount)||0, status:fStatus, due_date:fDue, description:fDesc };
   100→    editId ? updateMut.mutate({id:editId,data:payload}) : createMut.mutate(payload);
   101→    setShowModal(false);
   102→  }
   103→
   104→  const TABS=[{id:'pl',label:'P&L Chart'},{id:'invoices',label:'Invoices'},{id:'cash',label:'Cash Flow'},{id:'budget',label:'Budget'},{id:'costs',label:'Cost Codes'}] as const;
   105→
   106→  return (
   107→    <div className="space-y-6">
   108→      <div className="flex items-center justify-between">
   109→        <h1 className="text-3xl font-bold text-white">Accounting &amp; Finance</h1>
   110→        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg text-white font-medium transition-colors">
   111→          <Plus className="w-4 h-4"/>New Invoice
   112→        </button>
   113→      </div>
   114→
   115→      {overdueCount>0 && (
   116→        <div className="bg-red-900/30 border border-red-700 rounded-xl px-4 py-3 flex items-center gap-3">
   117→          <AlertCircle className="w-5 h-5 text-red-400 flex-shrink-0"/>
   118→          <p className="text-red-300 text-sm font-medium">{overdueCount} overdue invoice{overdueCount>1?'s':''} — {fmt(totalOverdue)} outstanding.</p>
   119→        </div>
   120→      )}
   121→
   122→      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
   123→        {[
   124→          {label:'Total Raised',  value:fmt(totalRaised),      icon:FileText,      col:'text-blue-400'},
   125→          {label:'Collected',     value:fmt(totalPaid),        icon:CheckCircle2,  col:'text-green-400'},
   126→          {label:'Outstanding',   value:fmt(totalOutstanding), icon:PoundSterling, col:'text-yellow-400'},
   127→          {label:'Overdue',       value:fmt(totalOverdue),     icon:AlertCircle,   col:'text-red-400'},
   128→        ].map(({label,value,icon:Icon,col})=>(
   129→          <div key={label} className="bg-gray-900 border border-gray-800 rounded-xl p-5">
   130→            <div className="flex items-center justify-between mb-3">
   131→              <p className="text-gray-400 text-sm">{label}</p>
   132→              <Icon className={`w-5 h-5 ${col}`}/>
   133→            </div>
   134→            <p className="text-2xl font-bold text-white">{value}</p>
   135→          </div>
   136→        ))}
   137→      </div>
   138→
   139→      <div className="flex gap-2 flex-wrap">
   140→        {TABS.map(t=>(
   141→          <button key={t.id} onClick={()=>setTab(t.id)}
   142→            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${tab===t.id?'bg-blue-600 text-white':'bg-gray-800 text-gray-400 hover:bg-gray-700 hover:text-white'}`}>
   143→            {t.label}
   144→          </button>
   145→        ))}
   146→      </div>
   147→
   148→      {tab==='pl' && (
   149→        <div className="bg-gray-900 border border-gray-800 rounded-xl p-6">
   150→          <h3 className="text-lg font-bold text-white mb-4">Revenue vs Profit — Last 7 Months</h3>
   151→          <ResponsiveContainer width="100%" height={360}>
   152→            <BarChart data={REV_DATA}>
   153→              <CartesianGrid strokeDasharray="3 3" stroke="#374151"/>
   154→              <XAxis dataKey="month" stroke="#9ca3af"/>
   155→              <YAxis stroke="#9ca3af" tickFormatter={(v:number)=>`£${(v/1000).toFixed(0)}K`}/>
   156→              <Tooltip contentStyle={{backgroundColor:'#111827',border:'1px solid #374151',borderRadius:8}} formatter={(v:number)=>`£${v.toLocaleString()}`}/>
   157→              <Legend/>
   158→              <Bar dataKey="revenue" name="Revenue" fill="#3b82f6" radius={[4,4,0,0]}/>
   159→              <Bar dataKey="costs"   name="Costs"   fill="#ef4444" radius={[4,4,0,0]}/>
   160→              <Bar dataKey="profit"  name="Profit"  fill="#10b981" radius={[4,4,0,0]}/>
   161→            </BarChart>
   162→          </ResponsiveContainer>
   163→        </div>
   164→      )}
   165→
   166→      {tab==='invoices' && (
   167→        <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
   168→          {isLoading ? <div className="p-8 text-center text-gray-400">Loading…</div> : (
   169→            <div className="overflow-x-auto">
   170→              <table className="w-full text-sm">
   171→                <thead className="bg-gray-800/60 border-b border-gray-700">
   172→                  <tr>{['Invoice #','Client','Project','Amount','Status','Due',''].map(h=>(
   173→                    <th key={h} className="px-4 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wide">{h}</th>
   174→                  ))}</tr>
   175→                </thead>
   176→                <tbody className="divide-y divide-gray-800">
   177→                  {invoices.map(inv=>(
   178→                    <tr key={String(inv.id)} className="hover:bg-gray-800/40 transition-colors">
   179→                      <td className="px-4 py-3 font-mono text-xs text-blue-400 font-bold">{String(inv.number??inv.invoice_number??'—')}</td>
   180→                      <td className="px-4 py-3 text-white font-medium">{String(inv.client??'—')}</td>
   181→                      <td className="px-4 py-3 text-gray-400 max-w-[180px] truncate">{String(inv.project??'—')}</td>
   182→                      <td className="px-4 py-3 text-white font-bold">{fmt(Number(inv.amount??0))}</td>
   183→                      <td className="px-4 py-3">
   184→                        <span className={`text-xs px-2 py-1 rounded-full font-medium ${STATUS_COLOUR[String(inv.status??'')]??'bg-gray-100 text-gray-600'}`}>
   185→                          {String(inv.status??'')}
   186→                        </span>
   187→                      </td>
   188→                      <td className="px-4 py-3 text-gray-400 text-sm">{String(inv.dueDate??inv.due_date??'—')}</td>
   189→                      <td className="px-4 py-3">
   190→                        <div className="flex items-center gap-2">
   191→                          {inv.status!=='paid' && (
   192→                            <button onClick={()=>updateMut.mutate({id:String(inv.id),data:{status:'paid'}})}
   193→                              className="text-xs px-2 py-1 bg-green-900/40 hover:bg-green-800 text-green-400 rounded font-medium transition-colors">
   194→                              Mark Paid
   195→                            </button>
   196→                          )}
   197→                          <button onClick={()=>openEdit(inv)} className="p-1 text-gray-400 hover:text-white rounded"><Edit2 className="w-3.5 h-3.5"/></button>
   198→                          <button onClick={()=>{if(confirm('Delete?'))deleteMut.mutate(String(inv.id));}} className="p-1 text-gray-400 hover:text-red-400 rounded"><Trash2 className="w-3.5 h-3.5"/></button>
   199→                        </div>
   200→                      </td>
   201→                    </tr>
   202→                  ))}
   203→                </tbody>
   204→              </table>
   205→            </div>
   206→          )}
   207→        </div>
   208→      )}
   209→
   210→      {tab==='cash' && (
   211→        <div className="bg-gray-900 border border-gray-800 rounded-xl p-6">
   212→          <h3 className="text-lg font-bold text-white mb-4">Cash Position — Last 7 Months</h3>
   213→          <ResponsiveContainer width="100%" height={400}>
   214→            <LineChart data={CASH_DATA}>
   215→              <CartesianGrid strokeDasharray="3 3" stroke="#374151"/>
   216→              <XAxis dataKey="month" stroke="#9ca3af"/>
   217→              <YAxis stroke="#9ca3af" tickFormatter={(v:number)=>`£${(v/1000).toFixed(0)}K`}/>
   218→              <Tooltip contentStyle={{backgroundColor:'#111827',border:'1px solid #374151',borderRadius:8}} formatter={(v:number)=>`£${v.toLocaleString()}`}/>
   219→              <Legend/>
   220→              <Line type="monotone" dataKey="cashIn"  name="Cash In"       stroke="#10b981" strokeWidth={2} dot={false}/>
   221→              <Line type="monotone" dataKey="cashOut" name="Cash Out"       stroke="#ef4444" strokeWidth={2} dot={false}/>
   222→              <Line type="monotone" dataKey="balance" name="Running Balance" stroke="#3b82f6" strokeWidth={2.5}/>
   223→            </LineChart>
   224→          </ResponsiveContainer>
   225→        </div>
   226→      )}
   227→
   228→      {tab==='budget' && (
   229→        <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
   230→          <div className="overflow-x-auto">
   231→            <table className="w-full text-sm">
   232→              <thead className="bg-gray-800/60 border-b border-gray-700">
   233→                <tr>{['Project','Contract Value','Budget','Spent','Remaining','% Used','Status'].map(h=>(
   234→                  <th key={h} className="px-5 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wide">{h}</th>
   235→                ))}</tr>
   236→              </thead>
   237→              <tbody className="divide-y divide-gray-800">
   238→                {projects.map(proj=>{
   239→                  const budget=Number(proj.budget??0), spent=Number(proj.spent??0);
   240→                  const pct=budget>0?(spent/budget)*100:0;
   241→                  const rag=pct>90?'red':pct>70?'amber':'green';
   242→                  return (
   243→                    <tr key={String(proj.id)} className="hover:bg-gray-800/40 transition-colors">
   244→                      <td className="px-5 py-4 font-medium text-white">{String(proj.name??'—')}</td>
   245→                      <td className="px-5 py-4 text-gray-300">{fmt(Number(proj.contractValue??proj.contract_value??0))}</td>
   246→                      <td className="px-5 py-4 font-semibold text-white">{fmt(budget)}</td>
   247→                      <td className="px-5 py-4 text-white">{fmt(spent)}</td>
   248→                      <td className="px-5 py-4 font-semibold text-green-400">{fmt(budget-spent)}</td>
   249→                      <td className="px-5 py-4 font-bold text-white">{pct.toFixed(1)}%</td>
   250→                      <td className="px-5 py-4">
   251→                        <span className={`text-xs px-2 py-1 rounded-full font-medium ${rag==='green'?'bg-green-900/40 text-green-400':rag==='amber'?'bg-yellow-900/40 text-yellow-400':'bg-red-900/40 text-red-400'}`}>
   252→                          {rag==='green'?'On Budget':rag==='amber'?'Watch':'Over Budget'}
   253→                        </span>
   254→                      </td>
   255→                    </tr>
   256→                  );
   257→                })}
   258→              </tbody>
   259→            </table>
   260→          </div>
   261→        </div>
   262→      )}
   263→
   264→      {tab==='costs' && (
   265→        <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
   266→          <div className="overflow-x-auto">
   267→            <table className="w-full text-sm">
   268→              <thead className="bg-gray-800/60 border-b border-gray-700">
   269→                <tr>{['Cost Code','Budgeted','Actual','Variance','% Spent'].map(h=>(
   270→                  <th key={h} className="px-5 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wide">{h}</th>
   271→                ))}</tr>
   272→              </thead>
   273→              <tbody className="divide-y divide-gray-800">
   274→                {[
   275→                  {code:'Labour',         budgeted:2400000, actual:1680000},
   276→                  {code:'Materials',      budgeted:2800000, actual:1960000},
   277→                  {code:'Plant',          budgeted:800000,  actual:560000 },
   278→                  {code:'Subcontractors', budgeted:1200000, actual:780000 },
   279→                  {code:'Overheads',      budgeted:600000,  actual:480000 },
   280→                ].map(row=>{
   281→                  const pct=(row.actual/row.budgeted)*100;
   282→                  return (
   283→                    <tr key={row.code} className="hover:bg-gray-800/40 transition-colors">
   284→                      <td className="px-5 py-4 font-medium text-white">{row.code}</td>
   285→                      <td className="px-5 py-4 font-semibold text-white">{fmt(row.budgeted)}</td>
   286→                      <td className="px-5 py-4 text-white">{fmt(row.actual)}</td>
   287→                      <td className="px-5 py-4 font-semibold text-green-400">{fmt(row.budgeted-row.actual)}</td>
   288→                      <td className="px-5 py-4 font-bold text-white">
   289→                        <div className="flex items-center gap-2">
   290→                          <div className="flex-1 h-2 bg-gray-700 rounded-full max-w-[80px]">
   291→                            <div className="h-full bg-blue-500 rounded-full" style={{width:`${Math.min(pct,100)}%`}}/>
   292→                          </div>
   293→                          {pct.toFixed(1)}%
   294→                        </div>
   295→                      </td>
   296→                    </tr>
   297→                  );
   298→                })}
   299→              </tbody>
   300→            </table>
   301→          </div>
   302→        </div>
   303→      )}
   304→
   305→      {showModal && (
   306→        <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4">
   307→          <div className="bg-gray-900 border border-gray-700 rounded-2xl w-full max-w-lg shadow-2xl">
   308→            <div className="flex items-center justify-between px-6 py-4 border-b border-gray-800">
   309→              <h2 className="text-lg font-bold text-white">{editId?'Edit Invoice':'New Invoice'}</h2>
   310→              <button onClick={()=>setShowModal(false)} className="text-gray-400 hover:text-white"><X className="w-5 h-5"/></button>
   311→            </div>
   312→            <div className="p-6 space-y-4">
   313→              <div className="grid grid-cols-2 gap-4">
   314→                <div>
   315→                  <label className="block text-xs font-medium text-gray-400 mb-1">Invoice Number</label>
   316→                  <input value={fNum} onChange={e=>setFNum(e.target.value)} className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-blue-500"/>
   317→                </div>
   318→                <div>
   319→                  <label className="block text-xs font-medium text-gray-400 mb-1">Status</label>
   320→                  <select value={fStatus} onChange={e=>setFStatus(e.target.value)} className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-blue-500">
   321→                    {INVOICE_STATUSES.map(s=><option key={s} value={s}>{s}</option>)}
   322→                  </select>
   323→                </div>
   324→              </div>
   325→              <div>
   326→                <label className="block text-xs font-medium text-gray-400 mb-1">Client *</label>
   327→                <input value={fClient} onChange={e=>setFClient(e.target.value)} placeholder="Client name" className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-blue-500"/>
   328→              </div>
   329→              <div>
   330→                <label className="block text-xs font-medium text-gray-400 mb-1">Project</label>
   331→                <select value={fProject} onChange={e=>setFProject(e.target.value)} className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-blue-500">
   332→                  <option value="">— Select project —</option>
   333→                  {projects.map(p=><option key={String(p.id)} value={String(p.name)}>{String(p.name)}</option>)}
   334→                </select>
   335→              </div>
   336→              <div className="grid grid-cols-2 gap-4">
   337→                <div>
   338→                  <label className="block text-xs font-medium text-gray-400 mb-1">Amount (£) *</label>
   339→                  <input type="number" value={fAmount} onChange={e=>setFAmount(e.target.value)} placeholder="0.00" className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-blue-500"/>
   340→                </div>
   341→                <div>
   342→                  <label className="block text-xs font-medium text-gray-400 mb-1">Due Date</label>
   343→                  <input type="date" value={fDue} onChange={e=>setFDue(e.target.value)} className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-blue-500"/>
   344→                </div>
   345→              </div>
   346→              <div>
   347→                <label className="block text-xs font-medium text-gray-400 mb-1">Description</label>
   348→                <textarea value={fDesc} onChange={e=>setFDesc(e.target.value)} rows={2} placeholder="Works description…" className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm resize-none focus:outline-none focus:border-blue-500"/>
   349→              </div>
   350→            </div>
   351→            <div className="flex gap-3 px-6 py-4 border-t border-gray-800">
   352→              <button onClick={handleSave} className="flex-1 bg-blue-600 hover:bg-blue-700 text-white rounded-lg py-2 text-sm font-semibold transition-colors">
   353→                {editId?'Save Changes':'Create Invoice'}
   354→              </button>
   355→              <button onClick={()=>setShowModal(false)} className="flex-1 bg-gray-800 hover:bg-gray-700 text-white rounded-lg py-2 text-sm font-semibold transition-colors">
   356→                Cancel
   357→              </button>
   358→            </div>
   359→          </div>
   360→        </div>
   361→      )}
   362→    </div>
   363→  );
   364→}
   365→

<system-reminder>
