  'Overdue':'bg-red-900/50 text-red-300',
};

const emptyForm = { subcontractor_name:'',utr_number:'',tax_period:'',gross_payment:'',cis_rate:'20',labour_only:'',materials:'',status:'Draft',payment_date:'',notes:'' };

export function CIS() {
  const { useList, useCreate, useUpdate, useDelete } = useCIS;
  const { data: raw = [], isLoading } = useList();
  const returns = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState('all');
  function setTab(key: string, filter: string) { setSubTab(key); setStatusFilter(filter); }
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });

  const filtered = returns.filter(r => {
    const name = String(r.subcontractor_name??'').toLowerCase();
    const matchSearch = name.includes(search.toLowerCase());
    const matchStatus = statusFilter === 'All' || r.status === statusFilter;
    return matchSearch && matchStatus;
  });

  const totalGross = returns.reduce((s,r)=>s+Number(r.gross_payment??0),0);
  const totalDeduction = returns.reduce((s,r)=>{
    const gross = Number(r.gross_payment??0);
    const materials = Number(r.materials??0);
    const rate = Number(r.cis_rate??20)/100;
    return s + (gross - materials) * rate;
  },0);
  const submittedCount = returns.filter(r=>r.status==='Submitted').length;
  const overdueCount = returns.filter(r=>r.status==='Overdue').length;

  function calcDeduction(r: AnyRow) {
    const gross = Number(r.gross_payment??0);
    const materials = Number(r.materials??0);
    const rate = Number(r.cis_rate??20)/100;
    return (gross - materials) * rate;
  }
  function calcNet(r: AnyRow) {
    return Number(r.gross_payment??0) - calcDeduction(r);
  }

  function openCreate() { setEditing(null); setForm({ ...emptyForm }); setShowModal(true); }
  function openEdit(r: AnyRow) {
    setEditing(r);
    setForm({ subcontractor_name:String(r.subcontractor_name??''),utr_number:String(r.utr_number??''),tax_period:String(r.tax_period??''),gross_payment:String(r.gross_payment??''),cis_rate:String(r.cis_rate??'20'),labour_only:String(r.labour_only??''),materials:String(r.materials??''),status:String(r.status??'Draft'),payment_date:String(r.payment_date??''),notes:String(r.notes??'') });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const payload = { ...form, gross_payment:Number(form.gross_payment)||0, cis_rate:Number(form.cis_rate)||20, labour_only:Number(form.labour_only)||0, materials:Number(form.materials)||0 };
    if (editing) { await updateMutation.mutateAsync({ id:String(editing.id), data:payload }); toast.success('CIS return updated'); }
    else { await createMutation.mutateAsync(payload); toast.success('CIS return created'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this CIS return?')) return;
    await deleteMutation.mutateAsync(id); toast.success('CIS return deleted');
  }

  async function markSubmitted(r: AnyRow) {
    await updateMutation.mutateAsync({ id:String(r.id), data:{ status:'Submitted' } });
    toast.success('Marked as submitted to HMRC');
  }

  // Live calculation from form
  const formGross = Number(form.gross_payment)||0;
  const formMaterials = Number(form.materials)||0;
  const formRate = Number(form.cis_rate)||20;
  const formDeduction = (formGross - formMaterials) * (formRate/100);
  const formNet = formGross - formDeduction;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-white">CIS Returns</h1>
          <p className="text-sm text-gray-400 mt-1">Construction Industry Scheme — monthly deduction records</p>
        </div>
        <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 hover:bg-orange-700 text-white rounded-lg text-sm font-medium transition-colors">
          <Plus size={16}/><span>New Return</span>
        </button>
      </div>

      {overdueCount > 0 && (
        <div className="flex items-center gap-3 bg-red-900/30 border border-red-700 rounded-xl px-4 py-3">
          <AlertCircle size={18} className="text-red-400 flex-shrink-0"/>
          <p className="text-sm text-red-300"><span className="font-semibold">{overdueCount} overdue return{overdueCount>1?'s':''}</span> — submit to HMRC to avoid penalties.</p>
        </div>
      )}

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label:'Total Gross Payments', value:`£${totalGross.toLocaleString()}`, icon:PoundSterling, colour:'text-blue-400' },
          { label:'Total CIS Deducted', value:`£${Math.round(totalDeduction).toLocaleString()}`, icon:Calculator, colour:'text-orange-400' },
          { label:'Submitted', value:submittedCount, icon:CheckCircle, colour:'text-green-400' },
          { label:'Overdue', value:overdueCount, icon:Clock, colour:overdueCount>0?'text-red-400':'text-gray-400' },
        ].map(kpi=>(
          <div key={kpi.label} className="bg-gray-900 border border-gray-800 rounded-xl p-4">
            <div className="flex items-center justify-between mb-3">
              <p className="text-xs text-gray-400">{kpi.label}</p>
              <kpi.icon size={18} className={kpi.colour}/>
            </div>
            <p className={`text-2xl font-bold ${kpi.colour}`}>{kpi.value}</p>
          </div>
        ))}
      </div>

      <div className="flex gap-1 border-b border-gray-700">
        {([
          { key:'all', label:'All Returns', filter:'All', count:returns.length, cls:'' },
          { key:'draft', label:'Draft', filter:'Draft', count:returns.filter(r=>r.status==='Draft').length, cls:'' },
          { key:'submitted', label:'Submitted', filter:'Submitted', count:submittedCount, cls:'' },
          { key:'overdue', label:'Overdue', filter:'Overdue', count:overdueCount, cls:'bg-red-900/40 text-red-400' },
        ]).map(t=>(
          <button key={t.key} onClick={()=>setTab(t.key, t.filter)}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${subTab===t.key?'border-orange-500 text-orange-400':'border-transparent text-gray-400 hover:text-gray-200'}`}>
            {t.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full ${t.cls||'bg-gray-800 text-gray-400'}`}>{t.count}</span>
          </button>
        ))}
      </div>

      <div className="flex flex-wrap gap-3 items-center bg-gray-900 border border-gray-800 rounded-xl p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"/>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search subcontractor…"
            className="w-full pl-9 pr-4 py-2 text-sm bg-gray-800 border border-gray-700 rounded-lg text-white focus:outline-none focus:border-orange-500"/>
        </div>
        <select value={statusFilter} onChange={e=>setStatusFilter(e.target.value)}
          className="text-sm bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-orange-500">
          {['All',...STATUS_OPTIONS].map(s=><option key={s}>{s}</option>)}
        </select>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500"/></div>
      ) : (
        <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
          <table className="w-full text-sm">
            <thead className="bg-gray-800/60 border-b border-gray-700">
              <tr>{['Subcontractor','UTR','Tax Period','Gross','Materials','CIS Rate','Deduction','Net Pay','Status',''].map(h=>(
                <th key={h} className="px-4 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wide whitespace-nowrap">{h}</th>
              ))}</tr>
            </thead>
            <tbody className="divide-y divide-gray-800">
              {filtered.map(r=>{
                const deduction = calcDeduction(r);
                const net = calcNet(r);
                return (
                  <tr key={String(r.id)} className="hover:bg-gray-800/40 transition-colors">
                    <td className="px-4 py-3 font-medium text-white">{String(r.subcontractor_name??'—')}</td>
                    <td className="px-4 py-3 text-gray-400 font-mono text-xs">{String(r.utr_number??'—')}</td>
                    <td className="px-4 py-3 text-gray-300">{String(r.tax_period??'—')}</td>
                    <td className="px-4 py-3 text-white font-medium">£{Number(r.gross_payment??0).toLocaleString()}</td>
                    <td className="px-4 py-3 text-gray-400">£{Number(r.materials??0).toLocaleString()}</td>
                    <td className="px-4 py-3">
                      <span className="text-xs bg-blue-900/50 text-blue-300 px-2 py-0.5 rounded-full font-medium">{Number(r.cis_rate??20)}%</span>
                    </td>
                    <td className="px-4 py-3 font-semibold text-red-400">-£{Math.round(deduction).toLocaleString()}</td>
                    <td className="px-4 py-3 font-semibold text-green-400">£{Math.round(net).toLocaleString()}</td>
                    <td className="px-4 py-3">
                      <span className={`text-xs px-2 py-1 rounded-full font-medium ${statusColour[String(r.status??'')] ?? 'bg-gray-700 text-gray-300'}`}>
                        {String(r.status??'')}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-1">
                        {r.status === 'Draft' && (
                          <button onClick={()=>markSubmitted(r)} className="p-1.5 text-green-400 hover:bg-green-900/40 rounded" title="Submit">
                            <CheckCircle size={14}/>
                          </button>
                        )}
                        <button onClick={()=>openEdit(r)} className="p-1.5 text-gray-400 hover:text-blue-400 hover:bg-blue-900/30 rounded"><Edit2 size={14}/></button>
                        <button onClick={()=>handleDelete(String(r.id))} className="p-1.5 text-gray-400 hover:text-red-400 hover:bg-red-900/30 rounded"><Trash2 size={14}/></button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
          {filtered.length === 0 && (
            <div className="text-center py-16 text-gray-500">
              <Receipt size={40} className="mx-auto mb-3 opacity-30"/><p>No CIS returns found</p>
            </div>
          )}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-gray-900 border border-gray-700 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between px-6 py-4 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
              <h2 className="text-lg font-bold text-white">{editing?'Edit CIS Return':'New CIS Return'}</h2>
              <button onClick={()=>setShowModal(false)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400 hover:text-white"><X size={18}/></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              {(formGross > 0) && (
                <div className="grid grid-cols-3 gap-3 bg-gray-800 rounded-xl p-4 text-sm">
                  <div className="text-center"><p className="text-xs text-blue-400 mb-1">Gross Payment</p><p className="font-bold text-white">£{formGross.toLocaleString()}</p></div>
                  <div className="text-center"><p className="text-xs text-red-400 mb-1">CIS Deduction</p><p className="font-bold text-red-300">-£{Math.round(formDeduction).toLocaleString()}</p></div>
                  <div className="text-center"><p className="text-xs text-green-400 mb-1">Net to Pay</p><p className="font-bold text-green-300">£{Math.round(formNet).toLocaleString()}</p></div>
                </div>
              )}
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="block text-xs font-medium text-gray-400 mb-1">Subcontractor Name *</label>
                  <input required value={form.subcontractor_name} onChange={e=>setForm(f=>({...f,subcontractor_name:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">UTR Number</label>
                  <input value={form.utr_number} onChange={e=>setForm(f=>({...f,utr_number:e.target.value}))} placeholder="10-digit UTR"
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Tax Period</label>
                  <select value={form.tax_period} onChange={e=>setForm(f=>({...f,tax_period:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500">
                    <option value="">Select…</option>{TAX_PERIOD_OPTIONS.map(p=><option key={p}>{p}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Gross Payment (£)</label>
                  <input type="number" value={form.gross_payment} onChange={e=>setForm(f=>({...f,gross_payment:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Materials (£)</label>
                  <input type="number" value={form.materials} onChange={e=>setForm(f=>({...f,materials:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">CIS Deduction Rate</label>
                  <select value={form.cis_rate} onChange={e=>setForm(f=>({...f,cis_rate:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500">
                    {CIS_RATES.map(r=><option key={r.value} value={r.value}>{r.label}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Status</label>
                  <select value={form.status} onChange={e=>setForm(f=>({...f,status:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500">
                    {STATUS_OPTIONS.map(s=><option key={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Payment Date</label>
                  <input type="date" value={form.payment_date} onChange={e=>setForm(f=>({...f,payment_date:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div className="col-span-2">
                  <label className="block text-xs font-medium text-gray-400 mb-1">Notes</label>
                  <textarea rows={2} value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500 resize-none"/>
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={()=>setShowModal(false)}
                  className="flex-1 px-4 py-2 bg-gray-800 hover:bg-gray-700 rounded-lg text-sm text-white font-medium transition-colors">Cancel</button>
                <button type="submit" disabled={createMutation.isPending||updateMutation.isPending}
                  className="flex-1 px-4 py-2 bg-orange-600 hover:bg-orange-700 text-white rounded-lg text-sm font-medium transition-colors disabled:opacity-50">
                  {editing?'Update Return':'Create Return'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { HardHat, Users, Truck, ClipboardList, AlertTriangle, CheckCircle, MapPin, Building2, Layers } from 'lucide-react';
import { useProjects, useSafety, useEquipment, useDailyReports } from '../../hooks/useData';

type AnyRow = Record<string, unknown>;

type SubTab = 'overview' | 'projects' | 'reports' | 'equipment';

const TABS: { key: SubTab; label: string; icon: React.ElementType }[] = [
  { key: 'overview',   label: 'Overview',     icon: Layers },
  { key: 'projects',  label: 'Projects',     icon: Building2 },
  { key: 'reports',   label: 'Site Reports', icon: ClipboardList },
  { key: 'equipment', label: 'Equipment',    icon: Truck },
];

export function SiteOperations() {
  const { data: rawProjects = [] } = useProjects.useList();
  const { data: rawSafety = [] } = useSafety.useList();
  const { data: rawEquipment = [] } = useEquipment.useList();
  const { data: rawReports = [] } = useDailyReports.useList();

  const projects = rawProjects as AnyRow[];
  const safetyIncidents = rawSafety as AnyRow[];
  const equipment = rawEquipment as AnyRow[];
  const reports = rawReports as AnyRow[];

  const [subTab, setSubTab] = useState<SubTab>('overview');

  const activeProjects = projects.filter(p => p.status === 'Active' || p.status === 'active' || p.status === 'In Progress');
  const today = new Date().toISOString().slice(0,10);
  const todayReports = reports.filter(r => String(r.report_date??'') === today);
  const openIncidents = safetyIncidents.filter(i => i.status === 'Open' || i.status === 'Investigation');
  const equipmentInUse = equipment.filter(e => e.status === 'In Use');
  const faultedEquipment = equipment.filter(e => e.status === 'Fault Reported');
  const totalWorkersToday = todayReports.reduce((s,r) => s + Number(r.workers_on_site??0), 0);

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-3xl font-bold text-white">Site Operations</h1>
        <p className="text-sm text-gray-400 mt-1">Live site overview — today's activity across all projects</p>
      </div>

      {/* Summary KPIs */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label:'Active Projects', value:activeProjects.length, icon:Building2, colour:'text-blue-400' },
          { label:'Workers on Site Today', value:totalWorkersToday || '—', icon:Users, colour:'text-green-400' },
          { label:'Open Safety Incidents', value:openIncidents.length, icon:AlertTriangle, colour:openIncidents.length>0?'text-red-400':'text-gray-400' },
          { label:'Equipment In Use', value:equipmentInUse.length, icon:Truck, colour:'text-orange-400' },
        ].map(kpi=>(
          <div key={kpi.label} className="bg-gray-900 border border-gray-800 rounded-xl p-4">
            <div className="flex items-center justify-between mb-3">
              <p className="text-xs text-gray-400">{kpi.label}</p>
              <kpi.icon size={18} className={kpi.colour}/>
            </div>
            <p className={`text-2xl font-bold ${kpi.colour}`}>{kpi.value}</p>
          </div>
        ))}
      </div>

      {/* Sub-nav */}
      <div className="border-b border-gray-700 flex gap-1">
        {TABS.map(t => {
          const Icon = t.icon;
          return (
            <button
              key={t.key}
              onClick={() => setSubTab(t.key)}
              className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${
                subTab === t.key
                  ? 'border-orange-500 text-orange-400'
                  : 'border-transparent text-gray-400 hover:text-gray-200'
              }`}
            >
              <Icon size={14}/>{t.label}
            </button>
          );
        })}
      </div>

      {/* OVERVIEW */}
      {subTab === 'overview' && (
        <div className="space-y-4">
          {(openIncidents.length > 0 || faultedEquipment.length > 0) && (
            <div className="space-y-2">
              {openIncidents.length > 0 && (
                <div className="flex items-center gap-3 bg-red-900/30 border border-red-700 rounded-xl px-4 py-3">
                  <AlertTriangle size={16} className="text-red-400 flex-shrink-0"/>
                  <p className="text-sm text-red-300"><span className="font-semibold">{openIncidents.length} open safety incident{openIncidents.length>1?'s':''}</span> — requires immediate attention.</p>
                </div>
              )}
              {faultedEquipment.length > 0 && (
                <div className="flex items-center gap-3 bg-orange-900/30 border border-orange-700 rounded-xl px-4 py-3">
                  <Truck size={16} className="text-orange-400 flex-shrink-0"/>
                  <p className="text-sm text-orange-300"><span className="font-semibold">{faultedEquipment.length} equipment fault{faultedEquipment.length>1?'s':''}</span> — out of service.</p>
                </div>
              )}
            </div>
          )}

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Active projects */}
            <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
              <div className="px-5 py-4 border-b border-gray-800 flex items-center gap-2">
                <Building2 size={16} className="text-blue-400"/>
                <h2 className="font-semibold text-white text-sm">Active Projects</h2>
                <span className="text-xs bg-blue-900/40 text-blue-400 px-2 py-0.5 rounded-full ml-auto">{activeProjects.length}</span>
              </div>
              <div className="divide-y divide-gray-800">
                {activeProjects.length === 0 && <p className="p-5 text-sm text-gray-500 text-center">No active projects</p>}
                {activeProjects.slice(0,6).map(p=>{
                  const progress = Number(p.progress??p.completion_percentage??0);
                  return (
                    <div key={String(p.id)} className="px-5 py-3">
                      <div className="flex items-center justify-between mb-1.5">
                        <p className="font-medium text-white text-sm truncate">{String(p.name??p.title??'Unnamed')}</p>
                        <span className="text-xs text-gray-400 ml-2 flex-shrink-0">{progress}%</span>
                      </div>
                      <div className="h-1.5 bg-gray-800 rounded-full">
                        <div className="h-full bg-gradient-to-r from-orange-500 to-orange-600 rounded-full" style={{width:`${Math.min(progress,100)}%`}}/>
                      </div>
                      {!!p.location && <p className="text-xs text-gray-500 mt-1 flex items-center gap-1"><MapPin size={9}/>{String(p.location)}</p>}
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Today's daily reports */}
            <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
              <div className="px-5 py-4 border-b border-gray-800 flex items-center gap-2">
                <ClipboardList size={16} className="text-green-400"/>
                <h2 className="font-semibold text-white text-sm">Today's Site Reports</h2>
                <span className="text-xs bg-green-900/40 text-green-400 px-2 py-0.5 rounded-full ml-auto">{todayReports.length}</span>
              </div>
              <div className="divide-y divide-gray-800">
                {todayReports.length === 0 && <p className="p-5 text-sm text-gray-500 text-center">No reports submitted yet today</p>}
                {todayReports.map(r=>(
                  <div key={String(r.id)} className="px-5 py-3">
                    <div className="flex items-center justify-between">
                      <p className="text-sm text-gray-300 truncate">{String(r.work_carried_out??'No description')}</p>
                      <span className="text-xs text-gray-400 ml-2 flex-shrink-0 flex items-center gap-1"><Users size={10}/>{String(r.workers_on_site??0)}</span>
                    </div>
                    <p className="text-xs text-gray-500 mt-0.5">{String(r.weather??'')} {r.submitted_by?`· ${r.submitted_by}`:''}</p>
                  </div>
                ))}
              </div>
            </div>

            {/* Open safety incidents */}
            <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
              <div className="px-5 py-4 border-b border-gray-800 flex items-center gap-2">
                <AlertTriangle size={16} className="text-red-400"/>
                <h2 className="font-semibold text-white text-sm">Open Safety Incidents</h2>
                <span className={`text-xs px-2 py-0.5 rounded-full ml-auto font-medium ${openIncidents.length>0?'bg-red-900/40 text-red-400':'bg-gray-800 text-gray-400'}`}>{openIncidents.length}</span>
              </div>
              <div className="divide-y divide-gray-800">
                {openIncidents.length === 0 && <p className="p-5 text-sm text-gray-500 text-center">No open incidents — site running safely</p>}
                {openIncidents.slice(0,5).map(i=>{
                  const sev = String(i.severity??'');
                  const sevColour = sev==='Critical'?'bg-red-900/40 text-red-400':sev==='Serious'?'bg-orange-900/40 text-orange-400':'bg-yellow-900/40 text-yellow-400';
                  return (
                    <div key={String(i.id)} className="px-5 py-3">
                      <div className="flex items-center justify-between">
                        <p className="text-sm text-gray-300 truncate">{String(i.title??i.description??'Incident')}</p>
                        <span className={`text-xs px-2 py-0.5 rounded-full font-medium ml-2 flex-shrink-0 ${sevColour}`}>{sev}</span>
                      </div>
                      <p className="text-xs text-gray-500 mt-0.5">{String(i.date??i.incident_date??'')} {i.location?`· ${i.location}`:''}</p>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Equipment status */}
            <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
              <div className="px-5 py-4 border-b border-gray-800 flex items-center gap-2">
                <Truck size={16} className="text-orange-400"/>
                <h2 className="font-semibold text-white text-sm">Equipment Status</h2>
                <span className="text-xs bg-orange-900/40 text-orange-400 px-2 py-0.5 rounded-full ml-auto">{equipment.length} total</span>
              </div>
              <div className="divide-y divide-gray-800">
                {equipment.length === 0 && <p className="p-5 text-sm text-gray-500 text-center">No equipment registered</p>}
                {equipment.slice(0,6).map(e=>{
                  const st = String(e.status??'');
                  const stColour = st==='In Use'?'bg-blue-900/40 text-blue-400':st==='Fault Reported'?'bg-red-900/40 text-red-400':st==='Under Service'?'bg-yellow-900/40 text-yellow-400':'bg-green-900/40 text-green-400';
                  return (
                    <div key={String(e.id)} className="px-5 py-3 flex items-center justify-between">
                      <div>
                        <p className="text-sm font-medium text-white">{String(e.name??'Unknown')}</p>
                        <p className="text-xs text-gray-500">{String(e.category??'')} · {String(e.ownership??'')}</p>
                      </div>
                      <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${stColour}`}>{st}</span>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* PROJECTS */}
      {subTab === 'projects' && (
        <div className="space-y-4">
          {projects.length === 0 ? (
            <div className="bg-gray-900 border border-gray-800 rounded-xl text-center py-16 text-gray-500">
              <Building2 size={40} className="mx-auto mb-3 opacity-30"/><p>No projects found</p>
            </div>
          ) : (
            <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="bg-gray-800/60 border-b border-gray-700">
                    <tr>
                      {['Project','Location','Status','Progress','Budget','Start Date','End Date'].map(h=>(
                        <th key={h} className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wide">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-800">
                    {projects.map(p => {
                      const progress = Number(p.progress??p.completion_percentage??0);
                      const st = String(p.status??'');
                      const stColour = st==='Active'||st==='In Progress'?'bg-green-900/40 text-green-400':st==='Completed'?'bg-gray-700 text-gray-400':st==='Cancelled'?'bg-red-900/40 text-red-400':'bg-blue-900/40 text-blue-400';
                      return (
                        <tr key={String(p.id)} className="hover:bg-gray-800/40 transition-colors">
                          <td className="px-4 py-3 font-medium text-white">{String(p.name??p.title??'Unnamed')}</td>
                          <td className="px-4 py-3 text-gray-400">
                            {!!p.location && <span className="flex items-center gap-1"><MapPin size={10}/>{String(p.location)}</span>}
                          </td>
                          <td className="px-4 py-3">
                            <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${stColour}`}>{st}</span>
                          </td>
                          <td className="px-4 py-3">
                            <div className="flex items-center gap-2 min-w-[100px]">
                              <div className="flex-1 h-1.5 bg-gray-800 rounded-full">
                                <div className="h-full bg-gradient-to-r from-orange-500 to-orange-600 rounded-full" style={{width:`${Math.min(progress,100)}%`}}/>
                              </div>
                              <span className="text-xs text-gray-400">{progress}%</span>
                            </div>
                          </td>
                          <td className="px-4 py-3 text-gray-300">
                            {Number(p.budget??0)>0?`£${(Number(p.budget)/1000).toFixed(0)}k`:'—'}
                          </td>
                          <td className="px-4 py-3 text-gray-400 whitespace-nowrap">{String(p.start_date??'—')}</td>
                          <td className="px-4 py-3 text-gray-400 whitespace-nowrap">{String(p.end_date??p.expected_end_date??'—')}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      )}

      {/* REPORTS */}
      {subTab === 'reports' && (
        <div className="space-y-4">
          <div className="flex items-center gap-3">
            <span className="text-xs bg-green-900/40 text-green-400 px-3 py-1 rounded-full font-medium">{todayReports.length} today</span>
            <span className="text-xs bg-gray-800 text-gray-400 px-3 py-1 rounded-full font-medium">{reports.length} total</span>
          </div>
          {reports.length === 0 ? (
            <div className="bg-gray-900 border border-gray-800 rounded-xl text-center py-16 text-gray-500">
              <ClipboardList size={40} className="mx-auto mb-3 opacity-30"/><p>No site reports found</p>
            </div>
          ) : (
            <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="bg-gray-800/60 border-b border-gray-700">
                    <tr>
                      {['Date','Submitted By','Workers','Weather','Activities','Issues / Delays'].map(h=>(
                        <th key={h} className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wide">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-800">
                    {[...reports].sort((a,b)=>String(b.report_date??'').localeCompare(String(a.report_date??''))).map(r=>{
                      const isToday = String(r.report_date??'') === today;
                      return (
                        <tr key={String(r.id)} className="hover:bg-gray-800/40 transition-colors">
                          <td className="px-4 py-3 whitespace-nowrap">
                            <div className="flex items-center gap-1.5">
                              {isToday && <span className="text-xs bg-green-900/40 text-green-400 px-1.5 py-0.5 rounded font-medium">Today</span>}
                              <span className="text-gray-400 text-xs">{String(r.report_date??'—')}</span>
                            </div>
                          </td>
                          <td className="px-4 py-3 text-gray-300">{String(r.submitted_by??r.author??'—')}</td>
                          <td className="px-4 py-3">
                            <span className="flex items-center gap-1 text-gray-300"><Users size={12}/>{Number(r.workers_on_site??0)}</span>
                          </td>
                          <td className="px-4 py-3 text-gray-400 text-xs">{String(r.weather??'—')}</td>
                          <td className="px-4 py-3 text-gray-400 max-w-xs truncate">{String(r.work_carried_out??'—')}</td>
                          <td className="px-4 py-3">
                            {!!r.delays
                              ? <span className="text-xs text-orange-300 bg-orange-900/30 px-2 py-0.5 rounded-full">{String(r.delays)}</span>
                              : <span className="text-xs text-green-400">None</span>}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      )}

      {/* EQUIPMENT */}
      {subTab === 'equipment' && (
        <div className="space-y-4">
          <div className="flex gap-2 flex-wrap">
            {[
              { label:'In Use', count:equipmentInUse.length, colour:'bg-blue-900/40 text-blue-400' },
              { label:'Faults', count:faultedEquipment.length, colour:'bg-red-900/40 text-red-400' },
              { label:'Available', count:equipment.filter(e=>e.status==='Available').length, colour:'bg-green-900/40 text-green-400' },
              { label:'Total', count:equipment.length, colour:'bg-gray-800 text-gray-400' },
            ].map(b=>(
              <span key={b.label} className={`text-xs px-3 py-1 rounded-full font-medium ${b.colour}`}>{b.label}: {b.count}</span>
            ))}
          </div>
          {equipment.length === 0 ? (
            <div className="bg-gray-900 border border-gray-800 rounded-xl text-center py-16 text-gray-500">
              <Truck size={40} className="mx-auto mb-3 opacity-30"/><p>No equipment registered</p>
            </div>
          ) : (
            <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="bg-gray-800/60 border-b border-gray-700">
                    <tr>
                      {['Name','Category','Ownership','Status','Location','Next Service'].map(h=>(
                        <th key={h} className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wide">{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-800">
                    {equipment.map(e => {
                      const st = String(e.status??'');
                      const stColour = st==='In Use'?'bg-blue-900/40 text-blue-400':st==='Fault Reported'?'bg-red-900/40 text-red-400':st==='Under Service'?'bg-yellow-900/40 text-yellow-400':st==='Hired Out'?'bg-purple-900/40 text-purple-400':'bg-green-900/40 text-green-400';
                      return (
                        <tr key={String(e.id)} className="hover:bg-gray-800/40 transition-colors">
                          <td className="px-4 py-3 font-medium text-white">
                            <div className="flex items-center gap-2">
                              {st==='Fault Reported' && <AlertTriangle size={13} className="text-red-400 flex-shrink-0"/>}
                              {String(e.name??'Unknown')}
                            </div>
                          </td>
                          <td className="px-4 py-3 text-gray-400">{String(e.category??'—')}</td>
                          <td className="px-4 py-3 text-gray-400">{String(e.ownership??'—')}</td>
                          <td className="px-4 py-3">
                            <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${stColour}`}>{st}</span>
                          </td>
                          <td className="px-4 py-3 text-gray-400">
                            {!!e.location && <span className="flex items-center gap-1"><MapPin size={10}/>{String(e.location)}</span>}
                          </td>
                          <td className="px-4 py-3 text-gray-400 text-xs">{String(e.next_service??e.service_due??'—')}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// Suppress unused import warning
const _HardHat = HardHat;
void _HardHat;

import { useState } from 'react';
import { FileText, Plus, Search, TrendingUp, Clock, CheckCircle, Edit2, Trash2, X, ChevronRight, Building2, Calendar, PoundSterling } from 'lucide-react';
import { useTenders } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const STAGES = ['Identified','Pre-Qualification','ITT Issued','Pricing','Submitted','Interview','Won','Lost','Withdrawn'];
const TYPES = ['Design & Build','Traditional','Two Stage','Framework','Negotiated','Minor Works'];

const stageColour: Record<string,string> = {
  'Identified':'bg-gray-700 text-gray-300',
  'Pre-Qualification':'bg-blue-900/50 text-blue-300',
  'ITT Issued':'bg-purple-900/50 text-purple-300',
  'Pricing':'bg-yellow-900/50 text-yellow-300',
  'Submitted':'bg-orange-900/50 text-orange-300',
  'Interview':'bg-indigo-900/50 text-indigo-300',
  'Won':'bg-green-900/50 text-green-300',
  'Lost':'bg-red-900/50 text-red-300',
  'Withdrawn':'bg-gray-700 text-gray-400',
};

const PIPELINE_STAGES = ['Identified','Pre-Qualification','ITT Issued','Pricing','Submitted'];

const emptyForm = { project_name:'',client:'',type:'',value:'',submission_date:'',result_date:'',stage:'Identified',probability:'',notes:'' };

export function Tenders() {
  const { useList, useCreate, useUpdate, useDelete } = useTenders;
  const { data: raw = [], isLoading } = useList();
  const tenders = raw as AnyRow[];
  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [stageGroup, setStageGroup] = useState<'all'|'active'|'won'|'lost'>('all');
  const [search, setSearch] = useState('');
  const [stageFilter, setStageFilter] = useState('All');
  const [view, setView] = useState<'pipeline'|'list'>('pipeline');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });

  const GROUP_STAGES: Record<string, string[]> = {
    all: [],
    active: ['Identified','Pre-Qualification','ITT Issued','Pricing','Submitted','Interview'],
    won: ['Won'],
    lost: ['Lost','Withdrawn'],
  };

  const filtered = tenders.filter(t => {
    const name = String(t.project_name??'').toLowerCase();
    const client = String(t.client??'').toLowerCase();
    const matchSearch = name.includes(search.toLowerCase()) || client.includes(search.toLowerCase());
    const matchStage = stageFilter === 'All' || t.stage === stageFilter;
    const groupStages = GROUP_STAGES[stageGroup] ?? [];
    const matchGroup = groupStages.length === 0 || groupStages.includes(String(t.stage??''));
    return matchSearch && matchStage && matchGroup;
  });

  const totalValue = tenders.reduce((s,t)=>s+Number(t.value??0),0);
  const wonCount = tenders.filter(t=>t.stage==='Won').length;
  const activeCount = tenders.filter(t=>!['Won','Lost','Withdrawn'].includes(String(t.stage??''))).length;
  const winRate = tenders.filter(t=>['Won','Lost'].includes(String(t.stage??''))).length > 0
    ? Math.round((wonCount / tenders.filter(t=>['Won','Lost'].includes(String(t.stage??''))).length) * 100) : 0;

  function openCreate() { setEditing(null); setForm({ ...emptyForm }); setShowModal(true); }
  function openEdit(t: AnyRow) {
    setEditing(t);
    setForm({ project_name:String(t.project_name??''),client:String(t.client??''),type:String(t.type??''),value:String(t.value??''),submission_date:String(t.submission_date??''),result_date:String(t.result_date??''),stage:String(t.stage??'Identified'),probability:String(t.probability??''),notes:String(t.notes??'') });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const payload = { ...form, value:Number(form.value)||0, probability:Number(form.probability)||0 };
    if (editing) { await updateMutation.mutateAsync({ id:String(editing.id), data:payload }); toast.success('Tender updated'); }
    else { await createMutation.mutateAsync(payload); toast.success('Tender added'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this tender?')) return;
    await deleteMutation.mutateAsync(id); toast.success('Tender deleted');
  }

  async function advanceStage(t: AnyRow) {
    const idx = STAGES.indexOf(String(t.stage??''));
    if (idx < 0 || idx >= STAGES.length-1) return;
    await updateMutation.mutateAsync({ id:String(t.id), data:{stage:STAGES[idx+1]} });
    toast.success(`Advanced to ${STAGES[idx+1]}`);
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-white">Tender Pipeline</h1>
          <p className="text-sm text-gray-400 mt-1">Bid management & win/loss tracking</p>
        </div>
        <div className="flex items-center gap-3">
          <div className="flex bg-gray-800 rounded-lg p-1">
            {(['pipeline','list'] as const).map(v=>(
              <button key={v} onClick={()=>setView(v)}
                className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors capitalize ${view===v?'bg-gray-600 text-white shadow':'text-gray-400 hover:text-gray-200'}`}>
                {v}
              </button>
            ))}
          </div>
          <button onClick={openCreate} className="flex items-center gap-2 px-4 py-2 bg-orange-600 hover:bg-orange-700 text-white rounded-lg text-sm font-medium transition-colors">
            <Plus size={16}/><span>New Tender</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label:'Pipeline Value', value:`£${(totalValue/1000000).toFixed(1)}M`, icon:PoundSterling, colour:'text-blue-400' },
          { label:'Active Bids', value:activeCount, icon:Clock, colour:'text-orange-400' },
          { label:'Won', value:wonCount, icon:CheckCircle, colour:'text-green-400' },
          { label:'Win Rate', value:`${winRate}%`, icon:TrendingUp, colour:'text-purple-400' },
        ].map(kpi=>(
          <div key={kpi.label} className="bg-gray-900 border border-gray-800 rounded-xl p-4">
            <div className="flex items-center justify-between mb-3">
              <p className="text-xs text-gray-400">{kpi.label}</p>
              <kpi.icon size={18} className={kpi.colour}/>
            </div>
            <p className={`text-2xl font-bold ${kpi.colour}`}>{kpi.value}</p>
          </div>
        ))}
      </div>

      {/* Stage group tabs */}
      <div className="flex gap-1 border-b border-gray-700">
        {([
          { key:'all',    label:'All Tenders',      count:tenders.length },
          { key:'active', label:'In Progress',       count:tenders.filter(t=>GROUP_STAGES.active.includes(String(t.stage??''))).length },
          { key:'won',    label:'Won',               count:tenders.filter(t=>t.stage==='Won').length },
          { key:'lost',   label:'Lost / Withdrawn',  count:tenders.filter(t=>['Lost','Withdrawn'].includes(String(t.stage??''))).length },
        ] as const).map(tab=>(
          <button key={tab.key} onClick={()=>{ setStageGroup(tab.key); setStageFilter('All'); }}
            className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${stageGroup===tab.key?'border-orange-500 text-orange-400':'border-transparent text-gray-400 hover:text-gray-200'}`}>
            {tab.label}
            <span className={`text-xs px-1.5 py-0.5 rounded-full ${
              tab.key==='won' ? 'bg-green-900/40 text-green-400' :
              tab.key==='lost' ? 'bg-red-900/40 text-red-400' :
              'bg-gray-800 text-gray-400'
            }`}>{tab.count}</span>
          </button>
        ))}
      </div>

      {/* Search + filter */}
      <div className="flex flex-wrap gap-3 items-center bg-gray-900 border border-gray-800 rounded-xl p-4">
        <div className="relative flex-1 min-w-48">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400"/>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search project or client…"
            className="w-full pl-9 pr-4 py-2 text-sm bg-gray-800 border border-gray-700 rounded-lg text-white focus:outline-none focus:border-orange-500"/>
        </div>
        <select value={stageFilter} onChange={e=>setStageFilter(e.target.value)}
          className="text-sm bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-orange-500">
          {['All',...STAGES].map(s=><option key={s}>{s}</option>)}
        </select>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500"/></div>
      ) : view === 'pipeline' ? (
        /* Pipeline View */
        <div className="overflow-x-auto pb-4">
          <div className="flex gap-4 min-w-max">
            {PIPELINE_STAGES.map(stage => {
              const stageTenders = filtered.filter(t=>t.stage===stage);
              const stageValue = stageTenders.reduce((s,t)=>s+Number(t.value??0),0);
              return (
                <div key={stage} className="w-64 flex-shrink-0">
                  <div className="bg-gray-800 rounded-t-lg px-4 py-3 flex items-center justify-between">
                    <span className="text-xs font-semibold text-gray-300 uppercase tracking-wide">{stage}</span>
                    <span className="text-xs bg-gray-700 text-gray-300 px-2 py-0.5 rounded-full">{stageTenders.length}</span>
                  </div>
                  <div className="bg-gray-900 border border-gray-800 border-t-0 rounded-b-lg p-2 space-y-2 min-h-48">
                    {stageValue > 0 && <p className="text-xs text-center text-gray-500 py-1">£{(stageValue/1000).toFixed(0)}k</p>}
                    {stageTenders.map(t=>(
                      <div key={String(t.id)} className="bg-gray-800 border border-gray-700 rounded-lg p-3 hover:border-gray-600 transition-colors cursor-pointer" onClick={()=>openEdit(t)}>
                        <p className="font-medium text-sm text-white truncate">{String(t.project_name??'Untitled')}</p>
                        <p className="text-xs text-gray-400 mt-0.5 flex items-center gap-1"><Building2 size={10}/>{String(t.client??'—')}</p>
                        {!!t.value && <p className="text-xs font-semibold text-orange-400 mt-2">£{Number(t.value).toLocaleString()}</p>}
                        {!!t.submission_date && <p className="text-xs text-gray-500 flex items-center gap-1 mt-1"><Calendar size={10}/>{String(t.submission_date)}</p>}
                        {!!t.probability && <div className="mt-2">
                          <div className="flex items-center justify-between mb-0.5">
                            <span className="text-xs text-gray-500">Win prob.</span>
                            <span className="text-xs text-gray-400">{Number(t.probability)}%</span>
                          </div>
                          <div className="h-1 bg-gray-700 rounded-full">
                            <div className="h-full bg-orange-500 rounded-full" style={{width:`${Math.min(Number(t.probability),100)}%`}}/>
                          </div>
                        </div>}
                        <button onClick={e=>{e.stopPropagation();advanceStage(t);}} className="mt-2 w-full text-xs text-center text-orange-400 hover:text-orange-300 flex items-center justify-center gap-1 transition-colors">
                          Advance <ChevronRight size={12}/>
                        </button>
                      </div>
                    ))}
                    {stageTenders.length === 0 && <p className="text-xs text-center text-gray-600 py-4">No tenders</p>}
                  </div>
                </div>
              );
            })}
            {/* Won/Lost columns */}
            {(['Won','Lost'] as const).map(stage=>{
              const stageTenders = filtered.filter(t=>t.stage===stage);
              const isWon = stage === 'Won';
              return (
                <div key={stage} className="w-64 flex-shrink-0">
                  <div className={`rounded-t-lg px-4 py-3 flex items-center justify-between ${isWon?'bg-green-900/40':'bg-red-900/40'}`}>
                    <span className={`text-xs font-semibold uppercase tracking-wide ${isWon?'text-green-400':'text-red-400'}`}>{stage}</span>
                    <span className="text-xs bg-gray-800 text-gray-300 px-2 py-0.5 rounded-full">{stageTenders.length}</span>
                  </div>
                  <div className="bg-gray-900 border border-gray-800 border-t-0 rounded-b-lg p-2 space-y-2 min-h-48">
                    {stageTenders.map(t=>(
                      <div key={String(t.id)} className="bg-gray-800 border border-gray-700 rounded-lg p-3 cursor-pointer hover:border-gray-600 transition-colors" onClick={()=>openEdit(t)}>
                        <p className="font-medium text-sm text-white truncate">{String(t.project_name??'Untitled')}</p>
                        <p className="text-xs text-gray-400">{String(t.client??'—')}</p>
                        {!!t.value && <p className="text-xs font-semibold text-gray-300 mt-1">£{Number(t.value).toLocaleString()}</p>}
                      </div>
                    ))}
                    {stageTenders.length === 0 && <p className="text-xs text-center text-gray-600 py-4">No tenders</p>}
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      ) : (
        /* List View */
        <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
          <table className="w-full text-sm">
            <thead className="bg-gray-800/60 border-b border-gray-700">
              <tr>{['Project','Client','Type','Value','Submission','Stage',''].map(h=>(
                <th key={h} className="px-4 py-3 text-left text-xs font-semibold text-gray-400 uppercase tracking-wide">{h}</th>
              ))}</tr>
            </thead>
            <tbody className="divide-y divide-gray-800">
              {filtered.map(t=>(
                <tr key={String(t.id)} className="hover:bg-gray-800/40 transition-colors">
                  <td className="px-4 py-3 font-medium text-white">{String(t.project_name??'—')}</td>
                  <td className="px-4 py-3 text-gray-400">{String(t.client??'—')}</td>
                  <td className="px-4 py-3 text-gray-400">{String(t.type??'—')}</td>
                  <td className="px-4 py-3 text-white font-medium">£{Number(t.value??0).toLocaleString()}</td>
                  <td className="px-4 py-3 text-gray-400">{String(t.submission_date??'—')}</td>
                  <td className="px-4 py-3">
                    <span className={`text-xs px-2 py-1 rounded-full font-medium ${stageColour[String(t.stage??'')] ?? 'bg-gray-700 text-gray-300'}`}>
                      {String(t.stage??'')}
                    </span>
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-1">
                      <button onClick={()=>openEdit(t)} className="p-1.5 text-gray-400 hover:text-blue-400 hover:bg-blue-900/30 rounded"><Edit2 size={14}/></button>
                      <button onClick={()=>handleDelete(String(t.id))} className="p-1.5 text-gray-400 hover:text-red-400 hover:bg-red-900/30 rounded"><Trash2 size={14}/></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filtered.length === 0 && (
            <div className="text-center py-16 text-gray-500">
              <FileText size={40} className="mx-auto mb-3 opacity-30"/><p>No tenders found</p>
            </div>
          )}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-gray-900 border border-gray-700 rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between px-6 py-4 border-b border-gray-800 sticky top-0 bg-gray-900 z-10">
              <h2 className="text-lg font-bold text-white">{editing?'Edit Tender':'New Tender'}</h2>
              <button onClick={()=>setShowModal(false)} className="p-2 hover:bg-gray-800 rounded-lg text-gray-400 hover:text-white"><X size={18}/></button>
            </div>
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="col-span-2">
                  <label className="block text-xs font-medium text-gray-400 mb-1">Project Name *</label>
                  <input required value={form.project_name} onChange={e=>setForm(f=>({...f,project_name:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Client</label>
                  <input value={form.client} onChange={e=>setForm(f=>({...f,client:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Contract Type</label>
                  <select value={form.type} onChange={e=>setForm(f=>({...f,type:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500">
                    <option value="">Select…</option>{TYPES.map(t=><option key={t}>{t}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Estimated Value (£)</label>
                  <input type="number" value={form.value} onChange={e=>setForm(f=>({...f,value:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Stage</label>
                  <select value={form.stage} onChange={e=>setForm(f=>({...f,stage:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500">
                    {STAGES.map(s=><option key={s}>{s}</option>)}
                  </select>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Win Probability (%)</label>
                  <input type="number" min="0" max="100" value={form.probability} onChange={e=>setForm(f=>({...f,probability:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Submission Date</label>
                  <input type="date" value={form.submission_date} onChange={e=>setForm(f=>({...f,submission_date:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Result Date</label>
                  <input type="date" value={form.result_date} onChange={e=>setForm(f=>({...f,result_date:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500"/>
                </div>
                <div className="col-span-2">
                  <label className="block text-xs font-medium text-gray-400 mb-1">Notes</label>
                  <textarea rows={3} value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}
                    className="w-full bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white text-sm focus:outline-none focus:border-orange-500 resize-none"/>
                </div>
              </div>
              <div className="flex gap-3 pt-2">
                <button type="button" onClick={()=>setShowModal(false)}
                  className="flex-1 px-4 py-2 bg-gray-800 hover:bg-gray-700 rounded-lg text-sm text-white font-medium transition-colors">Cancel</button>
                <button type="submit" disabled={createMutation.isPending||updateMutation.isPending}
                  className="flex-1 px-4 py-2 bg-orange-600 hover:bg-orange-700 text-white rounded-lg text-sm font-medium transition-colors disabled:opacity-50">
                  {editing?'Update Tender':'Create Tender'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { MapPin, Users, AlertTriangle, CheckCircle, Clock, Building2, Layers, Navigation2, CloudRain, Sun, Cloud, FileText, ShieldAlert } from 'lucide-react';
import { useProjects, useDailyReports, useSafety } from '../../hooks/useData';

type AnyRow = Record<string, unknown>;

const WEATHER_ICONS: Record<string, React.ReactNode> = {
  'Sunny': <Sun size={14} className="text-yellow-400"/>,
  'Partly Cloudy': <Cloud size={14} className="text-gray-400"/>,
  'Light Rain': <CloudRain size={14} className="text-blue-400"/>,
  'Heavy Rain': <CloudRain size={14} className="text-blue-500"/>,
  'Overcast': <Cloud size={14} className="text-gray-500"/>,
};

function WeatherIcon({ weather }: { weather: string }) {
  return <>{WEATHER_ICONS[weather] ?? <Cloud size={14} className="text-gray-400"/>}</>;
}

type SubTab = 'live' | 'reports' | 'safety';

const TABS: { key: SubTab; label: string; icon: React.ElementType }[] = [
  { key: 'live',    label: 'Live View',     icon: Layers },
  { key: 'reports', label: 'Daily Reports', icon: FileText },
  { key: 'safety',  label: 'Safety',        icon: ShieldAlert },
];

export function FieldView() {
  const { data: rawProjects = [] } = useProjects.useList();
  const { data: rawReports = [], isLoading: loadingReports } = useDailyReports.useList();
  const { data: rawSafety = [], isLoading: loadingSafety } = useSafety.useList();

  const projects = rawProjects as AnyRow[];
  const reports = rawReports as AnyRow[];
  const incidents = rawSafety as AnyRow[];

  const [subTab, setSubTab] = useState<SubTab>('live');
  const [selectedProject, setSelectedProject] = useState<string>('all');

  const today = new Date().toISOString().slice(0,10);
  const activeProjects = projects.filter(p => !['Completed','Cancelled'].includes(String(p.status??'')));
  const displayProjects = selectedProject === 'all' ? activeProjects : activeProjects.filter(p => String(p.id) === selectedProject);

  function getProjectReport(projectId: string) {
    return reports.find(r => String(r.project_id??'') === projectId && String(r.report_date??'') === today);
  }

  function getProjectIncidents(projectId: string) {
    return incidents.filter(i => String(i.project_id??'') === projectId && !['Closed'].includes(String(i.status??'')));
  }

  const openIncidents = incidents.filter(i => !['Closed'].includes(String(i.status??'')));
  const todayReports = reports.filter(r => String(r.report_date??'') === today);

  const sevColour = (sev: string) =>
    sev==='Critical'?'bg-red-900/50 text-red-300':sev==='Serious'?'bg-orange-900/50 text-orange-300':'bg-yellow-900/50 text-yellow-300';

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="text-3xl font-bold text-white">Field View</h1>
          <p className="text-sm text-gray-400 mt-1">Live site-by-site overview — {today}</p>
        </div>
        {subTab === 'live' && (
          <select value={selectedProject} onChange={e=>setSelectedProject(e.target.value)}
            className="text-sm bg-gray-800 border border-gray-700 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-orange-500">
            <option value="all">All Active Projects ({activeProjects.length})</option>
            {activeProjects.map(p=><option key={String(p.id)} value={String(p.id)}>{String(p.name??p.title??'Unnamed')}</option>)}
          </select>
        )}
      </div>

      {/* Summary strips */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label:'Sites Active Today', value:activeProjects.length, icon:Building2, colour:'text-blue-400' },
          { label:'Reports Submitted', value:todayReports.length, icon:CheckCircle, colour:'text-green-400' },
          { label:'Total Workers', value:todayReports.reduce((s,r)=>s+Number(r.workers_on_site??0),0)||'—', icon:Users, colour:'text-orange-400' },
          { label:'Open Incidents', value:openIncidents.length, icon:AlertTriangle, colour:openIncidents.length>0?'text-red-400':'text-gray-400' },
        ].map(kpi=>(
          <div key={kpi.label} className="bg-gray-900 border border-gray-800 rounded-xl p-4">
            <div className="flex items-center justify-between mb-3">
              <p className="text-xs text-gray-400">{kpi.label}</p>
              <kpi.icon size={18} className={kpi.colour}/>
            </div>
            <p className={`text-2xl font-bold ${kpi.colour}`}>{kpi.value}</p>
          </div>
        ))}
      </div>

      {/* Sub-nav */}
      <div className="border-b border-gray-700 flex gap-1">
        {TABS.map(t => {
          const Icon = t.icon;
          return (
            <button
              key={t.key}
              onClick={() => setSubTab(t.key)}
              className={`flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors ${
                subTab === t.key
                  ? 'border-orange-500 text-orange-400'
                  : 'border-transparent text-gray-400 hover:text-gray-200'
              }`}
            >
              <Icon size={14}/>{t.label}
            </button>
          );
        })}
      </div>

      {/* LIVE VIEW */}
      {subTab === 'live' && (
        displayProjects.length === 0 ? (
          <div className="bg-gray-900 border border-gray-800 rounded-xl text-center py-16 text-gray-500">
            <Navigation2 size={40} className="mx-auto mb-3 opacity-30"/><p>No active projects</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
            {displayProjects.map(p => {
              const pid = String(p.id??'');
              const report = getProjectReport(pid);
              const openInc = getProjectIncidents(pid);
              const progress = Number(p.progress??p.completion_percentage??0);
              const hasReport = !!report;

              return (
                <div key={pid} className={`bg-gray-900 border-2 rounded-xl transition-colors ${hasReport?'border-green-800':'border-gray-800'}`}>
                  <div className="px-5 py-4 flex items-start justify-between border-b border-gray-800">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <h3 className="font-bold text-white">{String(p.name??p.title??'Unnamed')}</h3>
                        {hasReport
                          ? <span className="text-xs bg-green-900/40 text-green-400 px-2 py-0.5 rounded-full flex items-center gap-1"><CheckCircle size={10}/>Reported</span>
                          : <span className="text-xs bg-yellow-900/40 text-yellow-400 px-2 py-0.5 rounded-full flex items-center gap-1"><Clock size={10}/>No report yet</span>}
                      </div>
                      {!!p.location && <p className="text-xs text-gray-500 flex items-center gap-1 mt-0.5"><MapPin size={10}/>{String(p.location)}</p>}
                    </div>
                    <div className="text-right ml-3">
                      <p className="text-2xl font-black text-orange-500">{progress}%</p>
                      <p className="text-xs text-gray-500">complete</p>
                    </div>
                  </div>

                  <div className="px-5 py-3 border-b border-gray-800">
                    <div className="h-2 bg-gray-800 rounded-full">
                      <div className="h-full bg-gradient-to-r from-orange-500 to-orange-600 rounded-full transition-all" style={{width:`${Math.min(progress,100)}%`}}/>
                    </div>
                  </div>

                  {report && (
                    <div className="px-5 py-3 border-b border-gray-800 bg-green-900/10">
                      <div className="flex items-center gap-2 mb-1.5">
                        <WeatherIcon weather={String(report.weather??'')}/>
                        <span className="text-xs text-gray-400">{String(report.weather??'')} · <span className="font-medium text-gray-300">{Number(report.workers_on_site??0)} workers</span></span>
                      </div>
                      <p className="text-xs text-gray-400 line-clamp-2">{String(report.work_carried_out??'No work description')}</p>
                      {!!report.delays && <p className="text-xs text-orange-400 mt-1 flex items-center gap-1"><AlertTriangle size={10}/>Delays: {String(report.delays)}</p>}
                    </div>
                  )}

                  <div className="px-5 py-3 grid grid-cols-3 gap-3 text-center">
                    <div>
                      <p className="text-lg font-bold text-white">{Number(p.budget??0)>0?`£${(Number(p.budget)/1000).toFixed(0)}k`:'—'}</p>
                      <p className="text-xs text-gray-500">Budget</p>
                    </div>
                    <div>
                      <p className={`text-lg font-bold ${openInc.length>0?'text-red-400':'text-green-400'}`}>{openInc.length}</p>
                      <p className="text-xs text-gray-500">Open Incidents</p>
                    </div>
                    <div>
                      <p className="text-lg font-bold text-white">{Number(p.workers??0)||'—'}</p>
                      <p className="text-xs text-gray-500">Workforce</p>
                    </div>
                  </div>

                  {openInc.length > 0 && (
                    <div className="px-5 pb-4 space-y-1">
                      {openInc.slice(0,2).map(i=>(
                        <div key={String(i.id)} className="flex items-center gap-2 text-xs bg-red-900/30 border border-red-800 rounded-lg px-3 py-1.5">
                          <AlertTriangle size={11} className="text-red-400 flex-shrink-0"/>
                          <span className="text-gray-300 truncate">{String(i.title??i.description??'Incident')}</span>
                          <span className="ml-auto text-red-400 font-medium">{String(i.severity??'')}</span>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )
      )}

      {/* DAILY REPORTS */}
      {subTab === 'reports' && (
        loadingReports ? (
          <div className="text-center py-16 text-gray-400">Loading reports…</div>
        ) : reports.length === 0 ? (
          <div className="bg-gray-900 border border-gray-800 rounded-xl text-center py-16 text-gray-500">
            <FileText size={40} className="mx-auto mb-3 opacity-30"/><p>No reports found</p>
          </div>
        ) : (
          <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-gray-800/60 border-b border-gray-700">
                  <tr>
                    {['Date','Project','Submitted By','Workers','Weather','Work Carried Out','Delays'].map(h=>(
                      <th key={h} className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wide">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-800">
                  {[...reports].sort((a,b)=>String(b.report_date??'').localeCompare(String(a.report_date??''))).map(r => {
                    const isToday = String(r.report_date??'') === today;
                    return (
                      <tr key={String(r.id)} className="hover:bg-gray-800/40 transition-colors">
                        <td className="px-4 py-3 whitespace-nowrap">
                          <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${isToday?'bg-green-900/40 text-green-400':'text-gray-400'}`}>
                            {String(r.report_date??'—')}
                          </span>
                        </td>
                        <td className="px-4 py-3 font-medium text-white">{String(r.project_name??r.project??'—')}</td>
                        <td className="px-4 py-3 text-gray-400">{String(r.submitted_by??r.author??'—')}</td>
                        <td className="px-4 py-3 text-center">
                          <span className="flex items-center gap-1 text-gray-300"><Users size={12}/>{Number(r.workers_on_site??0)}</span>
                        </td>
                        <td className="px-4 py-3">
                          <span className="flex items-center gap-1 text-gray-400">
                            <WeatherIcon weather={String(r.weather??'')}/>
                            {String(r.weather??'—')}
                          </span>
                        </td>
                        <td className="px-4 py-3 text-gray-400 max-w-xs truncate">{String(r.work_carried_out??'—')}</td>
                        <td className="px-4 py-3">
                          {!!r.delays
                            ? <span className="text-xs text-orange-300 bg-orange-900/30 px-2 py-0.5 rounded-full">{String(r.delays)}</span>
                            : <span className="text-xs text-gray-500">None</span>}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )
      )}

      {/* SAFETY */}
      {subTab === 'safety' && (
        loadingSafety ? (
          <div className="text-center py-16 text-gray-400">Loading incidents…</div>
        ) : incidents.length === 0 ? (
          <div className="bg-gray-900 border border-gray-800 rounded-xl text-center py-16 text-gray-500">
            <ShieldAlert size={40} className="mx-auto mb-3 opacity-30"/><p>No safety incidents recorded</p>
          </div>
        ) : (
          <div className="bg-gray-900 border border-gray-800 rounded-xl overflow-hidden">
            <div className="px-5 py-3 border-b border-gray-800 bg-gray-800/60 flex items-center justify-between">
              <p className="text-sm font-medium text-white">All Safety Incidents</p>
              <div className="flex gap-2">
                <span className="text-xs bg-red-900/40 text-red-400 px-2 py-0.5 rounded-full">{openIncidents.length} open</span>
                <span className="text-xs bg-gray-700 text-gray-400 px-2 py-0.5 rounded-full">{incidents.length} total</span>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-gray-800/60 border-b border-gray-700">
                  <tr>
                    {['Date','Title','Type','Severity','Location','Status'].map(h=>(
                      <th key={h} className="text-left px-4 py-3 text-xs font-semibold text-gray-400 uppercase tracking-wide">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-800">
                  {[...incidents].sort((a,b)=>String(b.date??b.incident_date??'').localeCompare(String(a.date??a.incident_date??''))).map(i => {
                    const sev = String(i.severity??'');
                    const st = String(i.status??'');
                    const stColour = st==='Closed'?'bg-gray-700 text-gray-400':st==='Investigation'?'bg-purple-900/50 text-purple-300':'bg-red-900/50 text-red-300';
                    return (
                      <tr key={String(i.id)} className="hover:bg-gray-800/40 transition-colors">
                        <td className="px-4 py-3 text-gray-400 whitespace-nowrap">{String(i.date??i.incident_date??'—')}</td>
                        <td className="px-4 py-3 font-medium text-white">{String(i.title??i.description??'Incident')}</td>
                        <td className="px-4 py-3 text-gray-400">{String(i.type??i.incident_type??'—')}</td>
                        <td className="px-4 py-3">
                          {!!sev && <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${sevColour(sev)}`}>{sev}</span>}
                        </td>
                        <td className="px-4 py-3 text-gray-400">
                          {!!i.location && <span className="flex items-center gap-1"><MapPin size={10}/>{String(i.location)}</span>}
                        </td>
                        <td className="px-4 py-3">
                          <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${stColour}`}>{st}</span>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )
      )}
    </div>
  );
}

import { useState } from 'react';
import { Layers, Plus, Search, Eye, Edit2, Trash2, X, FileImage } from 'lucide-react';
import { useDocuments } from '../../hooks/useData';
import { toast } from 'sonner';

type AnyRow = Record<string, unknown>;

const DISCIPLINES = ['Architecture','Structural','MEP – Mechanical','MEP – Electrical','MEP – Plumbing','Civil','Landscape','Interior','Fire','Other'];
const STATUSES = ['Preliminary','For Coordination','For Construction','For Information','Superseded','As-Built'];
const SCALES = ['1:5','1:10','1:20','1:50','1:100','1:200','1:500','NTS'];

const statusColour: Record<string,string> = {
  'Preliminary':'bg-gray-700 text-gray-300',
  'For Coordination':'bg-yellow-900/50 text-yellow-300',
  'For Construction':'bg-green-900/50 text-green-300',
  'For Information':'bg-blue-900/50 text-blue-300',
  'Superseded':'bg-orange-900/50 text-orange-300',
  'As-Built':'bg-purple-900/50 text-purple-300',
};

const emptyForm = { title:'',document_type:'Drawing',discipline:'Architecture',revision:'P01',status:'Preliminary',file_url:'',project_id:'',author:'',date_issued:'',description:'',drawing_number:'',scale:'1:100' };

export function Drawings() {
  const { useList, useCreate, useUpdate, useDelete } = useDocuments;
  const { data: raw = [], isLoading } = useList();
  const allDocs = raw as AnyRow[];
  const drawings = allDocs.filter(d => String(d.document_type??'').toLowerCase().includes('draw') || String(d.document_type??'') === 'Drawing' || !d.document_type);

  const createMutation = useCreate();
  const updateMutation = useUpdate();
  const deleteMutation = useDelete();

  const [subTab, setSubTab] = useState('all');
  function setTab(key: string, filter: string) { setSubTab(key); setStatusFilter(filter); }
  const [search, setSearch] = useState('');
  const [disciplineFilter, setDisciplineFilter] = useState('All');
  const [statusFilter, setStatusFilter] = useState('All');
  const [view, setView] = useState<'grid'|'list'>('grid');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<AnyRow | null>(null);
  const [form, setForm] = useState({ ...emptyForm });

  const filtered = drawings.filter(d => {
    const title = String(d.title??'').toLowerCase();
    const num = String(d.drawing_number??d.title??'').toLowerCase();
    const matchSearch = title.includes(search.toLowerCase()) || num.includes(search.toLowerCase());
    const matchDisc = disciplineFilter === 'All' || d.discipline === disciplineFilter;
    const matchStatus = statusFilter === 'All' || d.status === statusFilter;
    return matchSearch && matchDisc && matchStatus;
  });

  const forConstructionCount = drawings.filter(d=>d.status==='For Construction').length;
  const supersededCount = drawings.filter(d=>d.status==='Superseded').length;
  const latestRev = drawings.reduce((max,d) => {
    const r = String(d.revision??'');
    return r > max ? r : max;
  }, 'A');

  function openCreate() {
    setEditing(null);
    setForm({ ...emptyForm, date_issued:new Date().toISOString().slice(0,10), document_type:'Drawing' });
    setShowModal(true);
  }
  function openEdit(d: AnyRow) {
    setEditing(d);
    setForm({ title:String(d.title??''),document_type:'Drawing',discipline:String(d.discipline??'Architecture'),revision:String(d.revision??'P01'),status:String(d.status??'Preliminary'),file_url:String(d.file_url??''),project_id:String(d.project_id??''),author:String(d.author??''),date_issued:String(d.date_issued??''),description:String(d.description??''),drawing_number:String(d.drawing_number??''),scale:String(d.scale??'1:100') });
    setShowModal(true);
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const payload = { ...form, document_type: 'Drawing' };
    if (editing) { await updateMutation.mutateAsync({ id:String(editing.id), data:payload }); toast.success('Drawing updated'); }
    else { await createMutation.mutateAsync(payload); toast.success('Drawing registered'); }
    setShowModal(false);
  }

  async function handleDelete(id: string) {
    if (!confirm('Delete this drawing?')) return;
    await deleteMutation.mutateAsync(id); toast.success('Drawing deleted');
  }

  async function issueForConstruction(d: AnyRow) {
    await updateMutation.mutateAsync({ id:String(d.id), data:{ status:'For Construction' } });
    toast.success('Issued for Construction');
  }

  const uniqueDisciplines = ['All', ...Array.from(new Set(drawings.map(d=>String(d.discipline??'')).filter(Boolean)))];

