                </div>
                <div>
                  <label className="block text-xs font-medium text-gray-400 mb-1">Drawing Number</label>
                  <input value={form.drawing_number} onChange={e=>setForm(f=>({...f,drawing_number:e.target.value}))} placeholder="e.g. A-GA-001"
